"""O que aprendemos aqui foi como dar quebra de linha, no terminal para sair samuel e em baixo uchoa, Não faça : nome_sobrenome = "samuel" \ "uchoa" pois tem que ter o (n) ao lado do (\) e tem que ser ao lado da palavra que tem que ter a quebra de linha. """
nome_sobrenome = "Samuel\nUchoa"
print(nome_sobrenome)